package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetTrimDefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrimTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(true);
        assertTrue(format.getTrim());
    }

    @Test
    void testGetTrimFalseExplicit() {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(false);
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrimOnCustomFormat() {
        CSVFormat format = CSVFormat.newFormat(';').withTrim(true);
        assertTrue(format.getTrim());
    }
}
